module top_module(in, enable, clear, clk, out);input [5:0] in;
  input enable;
  input clear;
  input clk;
  output [5:0] out;

  reg [5:0] unused_states;

  always @ (posedge clk) begin
    if(enable && clear) begin
      unused_states = 6'b000000;
    end

    else if(enable) begin
      unused_states <= in;
    end
  end

  assign out = unused_states;

endmodule
